// Déduplication intelligente par URL + similarité de titre
const allResults = $input.all();

const articles = allResults.flatMap(item => item.json.results || []);

// Fonction de similarité simple (Levenshtein distance normalisée)
function similarity(s1, s2) {
  const longer = s1.length > s2.length ? s1 : s2;
  const shorter = s1.length > s2.length ? s2 : s1;
  if (longer.length === 0) return 1.0;
  const editDistance = levenshtein(longer, shorter);
  return (longer.length - editDistance) / longer.length;
}

function levenshtein(s1, s2) {
  const costs = [];
  for (let i = 0; i <= s1.length; i++) {
    let lastValue = i;
    for (let j = 0; j <= s2.length; j++) {
      if (i === 0) {
        costs[j] = j;
      } else if (j > 0) {
        let newValue = costs[j - 1];
        if (s1.charAt(i - 1) !== s2.charAt(j - 1)) {
          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
        }
        costs[j - 1] = lastValue;
        lastValue = newValue;
      }
    }
    if (i > 0) costs[s2.length] = lastValue;
  }
  return costs[s2.length];
}

// Déduplication
const seen = new Map();
const deduplicated = [];

for (const article of articles) {
  const url = article.url;
  const title = (article.title || '').toLowerCase();

  // Check exact URL match
  if (seen.has(url)) continue;

  // Check similar titles (>85% similarity)
  let isDuplicate = false;
  for (const [seenUrl, seenTitle] of seen.entries()) {
    if (similarity(title, seenTitle) > 0.85) {
      isDuplicate = true;
      break;
    }
  }

  if (!isDuplicate) {
    seen.set(url, title);
    deduplicated.push(article);
  }
}

console.log(`Articles avant déduplication: ${articles.length}`);
console.log(`Articles après déduplication: ${deduplicated.length}`);

return [{
  json: {
    articles: deduplicated,
    stats: {
      total_avant: articles.length,
      total_apres: deduplicated.length,
      doublons_elimines: articles.length - deduplicated.length
    }
  }
}]

