const response = $input.first().json;
const content = response.choices[0].message.content;

// Extraire le JSON (gérer les cas avec/sans backticks)
let jsonText = content.trim();
if (jsonText.startsWith('```json')) {
  jsonText = jsonText.replace(/```json\n?/g, '').replace(/```\n?$/g, '').trim();
} else if (jsonText.startsWith('```')) {
  jsonText = jsonText.replace(/```\n?/g, '').trim();
}

// Parser le JSON
let parsed;
try {
  parsed = JSON.parse(jsonText);
} catch (e) {
  // Fallback : chercher le JSON entre accolades
  const match = jsonText.match(/\{[\s\S]*\}/);
  if (!match) {
    throw new Error(`Impossible de parser le JSON. Erreur: ${e.message}\n\nContenu reçu:\n${content.substring(0, 500)}`);
  }
  parsed = JSON.parse(match[0]);
}

if (!parsed.articles || !Array.isArray(parsed.articles)) {
  throw new Error('Format JSON invalide : propriété "articles" manquante ou invalide');
}

console.log(`Articles analysés par le LLM : ${parsed.articles.length}`);
console.log('Répartition :', JSON.stringify(parsed.meta?.repartition_categories || {}));

return [{
  json: {
    articles: parsed.articles,
    meta: parsed.meta || {},
    date_veille: new Date().toISOString().split('T')[0]
  }
}];

