  }
}];

const data = $input.first().json;
const articles = data.articles || [];
const meta = data.meta || {};
const dateVeille = data.date_veille;

// Générer le nom de fichier : YYYY-MM-DD-veille-ia-bibliotheques.md
const filename = `${dateVeille}-veille-ia-bibliotheques.md`;

// Trier les articles par score décroissant
const sorted = [...articles].sort((a, b) => (b.score || 0) - (a.score || 0));

// Générer le frontmatter YAML pour Obsidian
const frontmatter = `---
title: "Veille IA & Big Data - Bibliothèques"
date: ${dateVeille}
type: veille
tags:
  - veille/ia
  - veille/big-data
  - bibliothèques
  - automatique
total_articles: ${sorted.length}
categories: ${JSON.stringify(meta.repartition_categories || {})}
---

`;

// Générer le contenu markdown
let markdown = frontmatter;

markdown += `# Veille IA & Big Data — Bibliothèques\n\n`;
markdown += `**Semaine du ${dateVeille}** | ${sorted.length} articles sélectionnés\n\n`;

if (meta.total_analyses) {
  markdown += `> **Analyse** : ${meta.total_analyses} articles scannés → ${meta.total_retenus || sorted.length} retenus (score ≥ 6/10)\n\n`;
}

// Table des matières par catégorie
const categories = {};
sorted.forEach(a => {
  const cat = a.categorie || 'AUTRE';
  if (!categories[cat]) categories[cat] = [];
  categories[cat].push(a);
});

markdown += `## 📑 Par catégorie\n\n`;
for (const [cat, items] of Object.entries(categories)) {
  const emoji = {
    'PROJET': '🚀',
    'ANALYTICS': '📈',
    'RECHERCHE': '🔬',
    'OUTIL': '🛠️',
    'TENDANCE': '📊'
  }[cat] || '📌';
  markdown += `- ${emoji} **${cat}** : ${items.length} article${items.length > 1 ? 's' : ''}\n`;
}

markdown += `\n---\n\n`;

// Articles détaillés par catégorie
for (const [cat, items] of Object.entries(categories)) {
  const emoji = {
    'PROJET': '🚀',
    'ANALYTICS': '📈',
    'RECHERCHE': '🔬',
    'OUTIL': '🛠️',
    'TENDANCE': '📊'
  }[cat] || '📌';

  markdown += `## ${emoji} ${cat}\n\n`;

  items.forEach((article, idx) => {
    markdown += `### ${idx + 1}. ${article.titre}\n\n`;
    markdown += `**Score** : ${article.score}/10 | **Source** : ${article.source || 'N/A'}${article.date_approx ? ` | **Date** : ${article.date_approx}` : ''}\n\n`;
    markdown += `🔗 [Lien vers l'article](${article.url})\n\n`;
    markdown += `${article.resume_contextualise}\n\n`;

    if (article.mots_cles && article.mots_cles.length > 0) {
      markdown += `**Tags** : ${article.mots_cles.map(t => `\`${t}\``).join(', ')}\n\n`;
    }

    markdown += `---\n\n`;
  });
}

// Section métadonnées
markdown += `## Métadonnées de la veille\n\n`;
markdown += `- **Date de génération** : ${new Date().toISOString()}\n`;
markdown += `- **Articles scannés** : ${meta.total_analyses || 'N/A'}\n`;
markdown += `- **Articles retenus** : ${sorted.length}\n`;
markdown += `- **Taux de sélection** : ${meta.total_analyses ? Math.round((sorted.length / meta.total_analyses) * 100) : 'N/A'}%\n\n`;

markdown += `---\n\n`;
markdown += `*Veille automatisée générée par N8N + Tavily + Groq*\n`;

return [{
  json: {
    filename: filename,
    markdown_content: markdown,
    filepath: `/data/obsidian/00_Inbox veille/n8n/${filename}`,    stats: {
      total_articles: sorted.length,
      categories: Object.keys(categories)
    }
  }
}];

const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const filepath = data.filepath;
const content = data.markdown_content;

// Créer le dossier si nécessaire
const dir = path.dirname(filepath);
if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

// Écrire le fichier
fs.writeFileSync(filepath, content, 'utf8');

console.log(`✅ Fichier créé : ${filepath}`);

return [{
  json: {
    success: true,
    filepath: filepath,
    filename: data.filename,
    message: `✅ Veille générée : ${data.filename}`
  }
}];
